#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *t3) {
    t3->tv_sec = t1->tv_sec - t2->tv_sec;
    t3->tv_usec = t1->tv_usec - t2->tv_usec;
    if (t3->tv_usec < 0) {
        t3->tv_sec--;
        t3->tv_usec += 1000000;
    }
}
#endif

#define min( a, b )			a > b ? b : a
#define ceilDiv( a, b )		( a + b - 1 ) / b
#define print( x )			printf( #x ": %lu\n", (unsigned long) x )
#define DEBUG				false

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53 
#define LATITUDE_POS 28	
#define OPEN 10000	

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations);
void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d);

void euclid(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; globalId++) {
        LatLong *latLong = locations + globalId;
        float *dist = distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat)*(lat - latLong->lat) + (lng - latLong->lng)*(lng - latLong->lng));
    }
}

int main(int argc, char* argv[])
{
    int    i=0;
    float lat, lng;
    int quiet=0,timing=0,platform=0,device=0;

    std::vector<Record> records;
    std::vector<LatLong> locations;
    char filename[100];
    int resultsCount=10;


    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    int numRecords = loadData(filename,records,locations);
    if (resultsCount > numRecords) resultsCount = numRecords;







    float *distances;

    LatLong *d_locations;
    float *d_distances;





    unsigned long threadsPerBlock = DEFAULT_THREADS_PER_BLOCK;
    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock ); 
    unsigned long maxGridX = 65535;
    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    if ( DEBUG )
    {
        print( threadsPerBlock );
        print( blocks ); 
        print( gridY );
        print( gridX );
    }




    distances = (float *)malloc(sizeof(float) * numRecords);
    d_locations = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    d_distances = (float *)malloc(sizeof(float) * numRecords);




    for (i = 0; i < numRecords; i++) {
        d_locations[i] = locations[i];
    }





#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

    euclid(d_locations,d_distances,numRecords,lat,lng);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif


    for (i = 0; i < numRecords; i++) {
        distances[i] = d_distances[i];
    }


    findLowest(records,distances,numRecords,resultsCount);


    if (!quiet)
    for(i=0;i<resultsCount;i++) {
      printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
    }
    free(distances);

    free(d_locations);
    free(d_distances);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}

int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations){
    FILE   *flist,*fp;
    int    i=0;
    char dbname[64];
    int recNum=0;



    flist = fopen(filename, "r");
    while(!feof(flist)) {





        if(fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            fgets(record.recString,49,fp);
            fgetc(fp); 
            if (feof(fp)) break;


            char substr[6];

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record *tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = &records[i];
    records[i] = records[minLoc];
    records[minLoc] = *tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;


    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              *r = atoi(argv[i]);
              break;
            case 'l': 
              if (argv[i][2]=='a') {
                *lat = atof(argv[i+1]);
              }
              else {
                *lng = atof(argv[i+1]);
              }
              i++;
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

